'use client';
import React, { useEffect, useRef, useState } from "react";
import Link from "next/link";
import { motion, useReducedMotion, useInView } from "framer-motion";

export default function Hero() {
  const fullText = "Smarter money decisions, made simple";
  const [typed, setTyped] = useState("");
  const [scrollY, setScrollY] = useState(0);
  const shapeARef = useRef<HTMLSpanElement | null>(null);
  const shapeBRef = useRef<HTMLSpanElement | null>(null);

  useEffect(() => {
    let i = 0;
    const id = setInterval(() => {
      i++;
      setTyped(fullText.slice(0, i));
      if (i >= fullText.length) clearInterval(id);
    }, 28);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    const onScroll = () => setScrollY(window.scrollY || 0);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <section className="relative overflow-hidden pt-28">
      <div className="absolute inset-0 -z-10 mesh-bg" />
      <span
        ref={shapeARef}
        style={{ transform: `translateY(${scrollY * 0.06}px)` }}
        className="pointer-events-none absolute left-[15%] top-10 h-64 w-64 rounded-full bg-[var(--color-primary-100)] blur-3xl opacity-60"
      />
      <span
        ref={shapeBRef}
        style={{ transform: `translateY(${scrollY * 0.04}px)` }}
        className="pointer-events-none absolute right-[12%] top-24 h-72 w-72 rounded-full bg-[var(--color-accent-50)] blur-3xl opacity-50"
      />

      <div className="mx-auto max-w-6xl px-6">
        <h1 className="text-4xl md:text-5xl font-semibold tracking-tight text-gray-900">
          {typed}
          <span className="caret">|</span>
        </h1>
        <p className="mt-4 max-w-2xl text-base md:text-lg text-gray-700">
          Pennywise turns budgeting and financial literacy into clear, personalized guidance you
          can act on today—backed by sources and tailored to your situation.
        </p>
        <div className="mt-8 flex items-center gap-3">
          <Link
            href="/signup"
            className="rounded-md bg-gray-900 px-4 py-2 text-sm text-white shadow-lg hover:opacity-90 animate-[floatPulse_6s_ease-in-out_infinite]"
          >
            Get Started Free
          </Link>
          <Link
            href="/login"
            className="rounded-md border px-4 py-2 text-sm hover:bg-black/5 animate-[floatPulse_6s_ease-in-out_infinite]"
          >
            Sign In
          </Link>
        </div>
        <p className="mt-6 text-xs text-gray-600">
          Private by design • Source-backed guidance
        </p>
      </div>

      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-3 text-gray-500">
        <div className="flex h-9 w-[22px] items-start justify-center rounded-full border">
          <span className="scroll-indicator-dot" />
        </div>
        <span className="text-xs">Scroll</span>
      </div>
    </section>
  );
}
